query:
-- Verify mecanicos
SELECT id, nome, grauConhecimento, especialidade, qtdePositivos, qtdeNegativos, ativo FROM `03_mecanicos` ORDER BY id;

-- Verify colaboradores
SELECT id, nome, cargo, ativo FROM `01_colaboradores` ORDER BY id;

-- Verify key configs
SELECT chave, valor FROM system_config WHERE chave IN ('meta_mensal','meta_ticket_medio','meta_os_mes','meta_os_semana','meta_os_dia','meta_nps','meta_reativacao','meta_colaborador_5','meta_colaborador_6') ORDER BY chave;

